    'html_source': '',
    'network_requests': [],
    'extracted_data': {},
    'matches': [],
    'errors': []
}

try:
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        context = browser.new_context()
        page = context.new_page()

        # Capture network requests
        def handle_request(req):
            results['network_requests'].append({
                'url': req.url,
                'method': req.method,
                'resource_type': req.resource_type
            })

        page.on('request', handle_request)

        print("Navigating to Solverde...")
        page.goto('https://www.solverde.pt', wait_until='networkidle', timeout=30000)
        time.sleep(3)

        print("Looking for 'Futebol' button...")
        # Try multiple selectors for "Futebol"
        futebol_selectors = [
            'text=Futebol',
            'a:has-text("Futebol")',
            'button:has-text("Futebol")',
            '[class*="futebol"]',
            'xpath=//a[contains(text(), "Futebol")]'
        ]

        clicked = False
        for sel in futebol_selectors:
            try:
                el = page.locator(sel).first
                if el.is_visible(timeout=2000):
                    print(f"Clicking with: {sel}")
                    el.click()
                    time.sleep(4)
                    clicked = True
                    break
            except Exception as e:
                continue

        if not clicked:
            print("Could not click Futebol, extracting current page data...")

        # Wait for dynamic content
        print("Waiting for content to load...")
        page.wait_for_timeout(5000)

        # Get full HTML
        results['html_source'] = page.content()
        print(f"HTML length: {len(results['html_source'])} chars")

        # Extract data directly from DOM
        print("\nExtracting data from DOM...")

        # Look for match elements
        match_data = []

        # Common betting selectors
        team_selectors = [
            '.team-name', '.team', '.competitor', '[class*="team"]',
            '.event-name', '.game-name', '[class*="match"]'
        ]

        odds_selectors = [
            '.odd', '.odds', '[class*="odd"]', '.price', '[class*="price"]'
        ]

        # Extract team names
        for sel in team_selectors:
            try:
                elements = page.locator(sel).all()
                if elements:
                    texts = [e.inner_text() for e in elements[:20] if e.inner_text().strip()]
                    if texts:
                        match_data.append({'selector': sel, 'teams': texts})
                        print(f"Found {len(texts)} team elements with: {sel}")
            except:
                pass

        # Extract odds
        for sel in odds_selectors:
            try:
                elements = page.locator(sel).all()
                if elements:
                    texts = [e.inner_text() for e in elements[:30] if e.inner_text().strip()]
                    if texts:
                        match_data.append({'selector': sel, 'odds': texts})
                        print(f"Found {len(texts)} odds with: {sel}")
            except:
                pass

        results['extracted_data']['dom_elements'] = match_data

        # Try to find any JSON in page
        js_data = page.evaluate('''() => {
            const data = {};
            // Check window.__data or similar
            for (let key in window) {
                if (key.includes('Data') || key.includes('State') || key.includes('Config')) {
                    try {
                        data[key] = typeof window[key];
                    } catch(e) {}
                }
            }
            return data;
        }''')
        results['extracted_data']['window_objects'] = js_data

        # Look for any element with betting-related text
        betting_texts = page.evaluate('''() => {
            const texts = [];
            const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
            let node;
            const keywords = ['jogo', 'porto', 'benfica', 'sporting', 'over', 'under', 'liga', 'aposta', 'odds', 'copa', 'mundial'];
            while (node = walker.nextNode()) {
                const txt = node.textContent.toLowerCase().trim();
                if (txt.length > 3 && keywords.some(k => txt.includes(k))) {
                    texts.push(node.textContent.trim().substring(0, 100));
                }
            }
            return [...new Set(texts)].slice(0, 50);
        }''')
        results['extracted_data']['betting_texts'] = betting_texts
        print(f"Found {len(betting_texts)} betting-related text snippets")

        # Check for any API calls made after click
        results['api_calls_after_click'] = [r for r in results['network_requests'] 
            if 'api' in r['url'].lower() or 'feed' in r['url'].lower() or 'sports' in r['url'].lower()]

        print(f"\nAPI calls after click: {len(results['api_calls_after_click'])}")

        browser.close()

except Exception as e:
    results['errors'].append(str(e))
    print(f"Error: {e}")

# Save results
with open(OUTPUT_FILE, 'w') as f:
    json.dump(results, f, indent=2)

print(f"\nSaved to {OUTPUT_FILE}")
print(f"HTML: {len(results['html_source'])} chars")
print(f"Network requests: {len(results['network_requests'])}")
print(f"DOM matches found: {len(results['extracted_data'].get('dom_elements', []))}")
print(f"Betting texts: {len(results['extracted_data'].get('betting_texts', []))}")
